mapper.select:
SELECT  FROM edu_major m LEFT JOIN sys_dept d ON m.dept_id = d.id

    AND m.major_name LIKE CONCAT('%', #{majorName}, '%')
    AND m.dept_id = #{deptId}
    AND m.status = #{status}

ORDER BY m.sort ASC, m.create_time DESC

mapper.update:
UPDATE edu_major
dept_id = #{deptId}, major_name = #{majorName}, major_code = #{majorCode}, edu_level = #{eduLevel}, study_year = #{studyYear}, sort = #{sort}, status = #{status}, update_time = #{updateTime},
WHERE id = #{id}
